#!/usr/bin/env node
/**
 * compress-sesion-thumbs.mjs — Resize + recompress the 17 Sesión thumbnails
 * generated by Wan 2.7 at 2K. They land at 5-7 MB each which is overkill
 * for card thumbnails. Targets ~150 KB each by capping the longer edge at
 * 800 px and re-encoding as JPEG quality 82.
 */
import sharp from 'sharp';
import { readdir, stat } from 'node:fs/promises';
import { join } from 'node:path';

const DIRS = ['public/app-thumbs/sesion-scenes', 'public/app-thumbs/sesion-poses'];
const MAX_EDGE = 800;
const QUALITY = 82;

let totalIn = 0;
let totalOut = 0;

for (const dir of DIRS) {
  const files = (await readdir(dir)).filter(f => f.endsWith('.jpg'));
  for (const f of files) {
    const path = join(dir, f);
    const inBytes = (await stat(path)).size;
    totalIn += inBytes;
    // sharp can read and write the same path safely (buffers internally)
    const buf = await sharp(path)
      .resize({ width: MAX_EDGE, height: MAX_EDGE, fit: 'inside', withoutEnlargement: true })
      .jpeg({ quality: QUALITY, mozjpeg: true })
      .toBuffer();
    await sharp(buf).toFile(path);
    const outBytes = (await stat(path)).size;
    totalOut += outBytes;
    console.log(`  ${f.padEnd(22)} ${(inBytes / 1024).toFixed(0).padStart(5)} KB → ${(outBytes / 1024).toFixed(0).padStart(4)} KB`);
  }
}

console.log(`\nTotal: ${(totalIn / 1024 / 1024).toFixed(1)} MB → ${(totalOut / 1024 / 1024).toFixed(1)} MB`);
console.log(`Saved ${((1 - totalOut / totalIn) * 100).toFixed(0)}%`);
